/**
 * Subtracts the given color from this color
 *
 * @param color the color
 * @return this color
 */
public Color sub(Color color) {
    this.r -= color.r;
    this.g -= color.g;
    this.b -= color.b;
    this.a -= color.a;
    return clamp();
}
